+async fn register_cloned_workspace(
+    client: &Client,
+    server: &str,
+    token: &Option<String>,
+    worker_id: &str,
+    workspace: &RegisteredWorkspaceRecord,
+    repo_path: &Path,
+) -> Result<()> {
+    let mut req = client.post(format!(
+        "{}/v1/agent/workspaces",
+        server.trim_end_matches('/')
